			Detail:            harnessDetail(info),
			ModelCount:        harnessModelCount(info),
			IsDefault:         false,
			LastCheckedAt:     strPtr(lastChecked),
			DefaultForProfile: []string{},
		}
		ps.Usage = buildUsage(entries, info.Name, agent.MatchHarness, now)
