   603	
   604	func providerDetail(p agentlib.ProviderInfo) string {
   605		if p.LastError != nil && strings.TrimSpace(p.LastError.Detail) != "" {
   606			return p.LastError.Detail
   607		}
   608		for _, ep := range p.EndpointStatus {
   609			if ep.LastError != nil && strings.TrimSpace(ep.LastError.Detail) != "" {
   610				return ep.LastError.Detail
   611			}
   612			if strings.TrimSpace(ep.Status) != "" && !strings.EqualFold(ep.Status, p.Status) {
   613				return ep.Status
   614			}
   615		}
   616		if strings.TrimSpace(p.Status) != "" {
   617			if strings.EqualFold(p.Status, "unknown") {
   618				return "not checked yet"
   619			}
   620			return p.Status
